import { useState, useEffect } from "react";
import KPICards from "./components/KPICards";
import DailyChart from "./components/DailyChart";
import MediaTable from "./components/MediaTable";
import Sidebar from "./components/Sidebar";
import Header from "./components/Header";

const API = "http://localhost:3001";

export default function App() {
  const [daily, setDaily] = useState(null);
  const [total, setTotal] = useState(null);
  const [media, setMedia] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchAll = async () => {
      try {
        setLoading(true);
        const [dailyRes, totalRes, mediaRes] = await Promise.all([
          fetch(`${API}/insights/daily`),
          fetch(`${API}/insights/total`),
          fetch(`${API}/media`),
        ]);

        if (!dailyRes.ok || !totalRes.ok || !mediaRes.ok) {
          throw new Error("One or more endpoints returned an error.");
        }

        const [dailyData, totalData, mediaData] = await Promise.all([
          dailyRes.json(),
          totalRes.json(),
          mediaRes.json(),
        ]);

        setDaily(dailyData);
        setTotal(totalData);
        setMedia(mediaData);
      } catch (err) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };

    fetchAll();
  }, []);

  const formattedTotal = total
  ? {
      profile_views:
        total?.profile_views?.data?.[0]?.total_value?.value ?? 0,

      followers:
        total?.followers?.data?.[0]?.values?.slice(-1)[0]?.value ?? 0,
    }
  : null;

  return (
    <div className="flex min-h-screen bg-[#0a0a0f] text-white font-sans">
      {/* Grain overlay */}
      <div className="pointer-events-none fixed inset-0 z-50 opacity-[0.025]"
        style={{ backgroundImage: "url(\"data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)' opacity='1'/%3E%3C/svg%3E\")", backgroundRepeat: "repeat", backgroundSize: "128px 128px" }}
      />

      <Sidebar />

      <div className="flex-1 flex flex-col min-w-0">
        <Header />

        <main className="flex-1 px-8 py-8 space-y-8 max-w-[1400px] w-full mx-auto">
          {error && (
            <div className="rounded-xl border border-red-500/30 bg-red-500/10 px-6 py-4 text-red-400 text-sm flex items-center gap-3">
              <svg className="w-4 h-4 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
              <span><strong>Error fetching data:</strong> {error}</span>
            </div>
          )}

          <KPICards data={formattedTotal} loading={loading} />
          <DailyChart data={daily} loading={loading} />
          <MediaTable data={media} loading={loading} />
        </main>
      </div>
    </div>
  );
}
